import React, { useState, useEffect } from "react";
import { api } from "../utils/api";

const TIP_LABEL = { fizicka: "Fizička osoba", pravna: "Pravna osoba" };

const EMPTY_FORM = { naziv: "", oib: "", tip: "fizicka", email: "", telefon: "", adresa: "", biljeske: "" };

function KlijentModal({ initial, onSave, onClose }) {
  const [form, setForm]   = useState(initial || EMPTY_FORM);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState("");
  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));
  const isEdit = !!initial;

  const submit = async () => {
    if (!form.naziv.trim()) { setError("Naziv je obavezan."); return; }
    setLoading(true); setError("");
    try { await onSave(form); onClose(); }
    catch (e) { setError(e.message); setLoading(false); }
  };

  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <span className="modal-title">{isEdit ? "Uredi klijenta" : "Novi klijent"}</span>
          <button className="btn-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {error && <div style={{ color: "var(--red)", marginBottom: 16, fontSize: 13 }}>⚠ {error}</div>}
          <div className="form-grid">
            <div className="form-group full">
              <label>Ime i prezime / naziv tvrtke *</label>
              <input placeholder="npr. Ivan Horvat ili Horvat d.o.o." value={form.naziv} onChange={(e) => set("naziv", e.target.value)} />
            </div>
            <div className="form-group">
              <label>Tip</label>
              <select value={form.tip} onChange={(e) => set("tip", e.target.value)}>
                <option value="fizicka">Fizička osoba</option>
                <option value="pravna">Pravna osoba</option>
              </select>
            </div>
            <div className="form-group">
              <label>OIB</label>
              <input
                placeholder="11 znamenki"
                maxLength={11}
                value={form.oib}
                onChange={(e) => set("oib", e.target.value.replace(/\D/g, ""))}
              />
            </div>
            <div className="form-group">
              <label>Email</label>
              <input type="email" placeholder="email@primjer.hr" value={form.email} onChange={(e) => set("email", e.target.value)} />
            </div>
            <div className="form-group">
              <label>Telefon</label>
              <input placeholder="+385 91 234 5678" value={form.telefon} onChange={(e) => set("telefon", e.target.value)} />
            </div>
            <div className="form-group full">
              <label>Adresa</label>
              <input placeholder="Ulica i broj, Grad" value={form.adresa} onChange={(e) => set("adresa", e.target.value)} />
            </div>
            <div className="form-group full">
              <label>Bilješke</label>
              <textarea placeholder="Interne napomene o klijentu..." value={form.biljeske} onChange={(e) => set("biljeske", e.target.value)} />
            </div>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Odustani</button>
          <button className="btn btn-primary" onClick={submit} disabled={loading}>
            {loading ? "Spremam..." : isEdit ? "Spremi izmjene" : "Dodaj klijenta"}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function KlijentiPage() {
  const [klijenti, setKlijenti] = useState([]);
  const [filter, setFilter]     = useState("");
  const [modal, setModal]       = useState(null); // null | "new" | klijent objekt (edit)
  const [detalj, setDetalj]     = useState(null); // klijent objekt za panel s detaljima

  const load = () => api.getKlijenti().then(setKlijenti);
  useEffect(() => { load(); }, []);

  const filtered = klijenti.filter((k) => {
    const q = filter.toLowerCase();
    return !q || k.naziv.toLowerCase().includes(q) || k.oib.includes(q);
  });

  const handleCreate = async (data) => { await api.createKlijent(data); await load(); };
  const handleUpdate = async (data) => { await api.updateKlijent(detalj.id, data); const fresh = await api.getKlijent(detalj.id); setDetalj(fresh); await load(); };
  const handleDelete = async (id) => {
    if (!window.confirm("Obrisati klijenta?")) return;
    await api.deleteKlijent(id);
    if (detalj?.id === id) setDetalj(null);
    load();
  };

  return (
    <div>
      <div className="page-header">
        <h2>Klijenti</h2>
        <p>Imenik svih klijenata ureda</p>
      </div>

      <div style={{ display: "flex", gap: 20, alignItems: "flex-start" }}>
        {/* ── Lista ── */}
        <div className="card" style={{ flex: 1, minWidth: 0 }}>
          <div className="card-header">
            <input
              style={{ border: "1px solid var(--cream)", borderRadius: 6, padding: "7px 12px", fontSize: 13, width: 240 }}
              placeholder="Pretraži po imenu ili OIB-u..."
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
            />
            <button className="btn btn-primary" onClick={() => setModal("new")}>+ Novi klijent</button>
          </div>

          {filtered.length === 0 ? (
            <div className="empty">
              <div className="empty-icon">👤</div>
              <p>{filter ? "Nema rezultata pretrage." : "Još nema klijenata. Dodajte prvog."}</p>
            </div>
          ) : (
            <table className="table">
              <thead>
                <tr>
                  <th>Naziv</th>
                  <th>Tip</th>
                  <th>OIB</th>
                  <th>Email</th>
                  <th>Telefon</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((k) => (
                  <tr
                    key={k.id}
                    style={{ cursor: "pointer", background: detalj?.id === k.id ? "var(--parchment)" : undefined }}
                    onClick={() => setDetalj(k)}
                  >
                    <td style={{ fontWeight: 500 }}>{k.naziv}</td>
                    <td>
                      <span style={{ fontSize: 12, background: "var(--cream)", borderRadius: 4, padding: "2px 7px" }}>
                        {TIP_LABEL[k.tip] || k.tip}
                      </span>
                    </td>
                    <td style={{ fontSize: 13, color: k.oib ? "var(--ink)" : "var(--ink-3)", fontFamily: "monospace" }}>
                      {k.oib || "—"}
                    </td>
                    <td style={{ fontSize: 13, color: "var(--ink-3)" }}>{k.email || "—"}</td>
                    <td style={{ fontSize: 13, color: "var(--ink-3)" }}>{k.telefon || "—"}</td>
                    <td>
                      <button className="btn btn-sm btn-danger" onClick={(e) => { e.stopPropagation(); handleDelete(k.id); }}>Briši</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        {/* ── Detalji ── */}
        {detalj && (
          <div className="card" style={{ width: 300, flexShrink: 0 }}>
            <div className="card-header">
              <span className="card-title">Detalji</span>
              <div style={{ display: "flex", gap: 6 }}>
                <button className="btn btn-ghost btn-sm" onClick={() => setModal(detalj)}>✏ Uredi</button>
                <button className="btn-close" onClick={() => setDetalj(null)}>×</button>
              </div>
            </div>
            <div className="card-body">
              <div style={{ marginBottom: 20 }}>
                <div style={{ fontSize: 18, fontWeight: 700, marginBottom: 4 }}>{detalj.naziv}</div>
                <span style={{ fontSize: 12, background: "var(--cream)", borderRadius: 4, padding: "2px 8px" }}>
                  {TIP_LABEL[detalj.tip] || detalj.tip}
                </span>
              </div>
              {[
                ["OIB",      detalj.oib,     true ],
                ["Email",    detalj.email,   false],
                ["Telefon",  detalj.telefon, false],
                ["Adresa",   detalj.adresa,  false],
              ].map(([label, value, mono]) => value ? (
                <div key={label} style={{ marginBottom: 12 }}>
                  <div style={{ fontSize: 11, textTransform: "uppercase", letterSpacing: ".5px", color: "var(--ink-3)", marginBottom: 2 }}>{label}</div>
                  <div style={{ fontSize: 14, fontFamily: mono ? "monospace" : undefined }}>{value}</div>
                </div>
              ) : null)}
              {detalj.biljeske && (
                <div style={{ marginTop: 16, paddingTop: 16, borderTop: "1px solid var(--cream)" }}>
                  <div style={{ fontSize: 11, textTransform: "uppercase", letterSpacing: ".5px", color: "var(--ink-3)", marginBottom: 6 }}>Bilješke</div>
                  <p style={{ fontSize: 13, lineHeight: 1.6, color: "var(--ink-2)", margin: 0 }}>{detalj.biljeske}</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {modal === "new" && <KlijentModal onSave={handleCreate} onClose={() => setModal(null)} />}
      {modal && modal !== "new" && (
        <KlijentModal initial={modal} onSave={handleUpdate} onClose={() => setModal(null)} />
      )}
    </div>
  );
}
